import java.io.*;
import java.nio.file.*;
import javax.servlet.*;
import javax.servlet.http.*;
import javax.servlet.annotation.WebServlet;

@WebServlet("/download")
public class FileDownloadServlet extends HttpServlet {
    private static final String UPLOADS_DIRECTORY = "uploads";
    
    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws ServletException, IOException {
        
        String filename = request.getParameter("filename");
        if (filename == null || filename.trim().isEmpty()) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Filename is required");
            return;
        }
        
        // Validate filename to prevent path traversal
        if (filename.contains("..") || filename.startsWith("/") || filename.startsWith("\\")) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid filename");
            return;
        }
        
        // Canonicalize the path to prevent directory traversal
        Path uploadsPath = Paths.get(UPLOADS_DIRECTORY).toAbsolutePath().normalize();
        Path filePath = uploadsPath.resolve(filename).toAbsolutePath().normalize();
        
        // Ensure the file is within the uploads directory
        if (!filePath.startsWith(uploadsPath)) {
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access denied");
            return;
        }
        
        // Check if file exists and is a regular file
        if (!Files.exists(filePath) || !Files.isRegularFile(filePath)) {
            response.sendError(HttpServletResponse.SC_NOT_FOUND, "File not found");
            return;
        }
        
        // Set appropriate content type based on file extension
        String contentType = getServletContext().getMimeType(filename);
        if (contentType == null) {
            contentType = "application/octet-stream";
        }
        response.setContentType(contentType);
        response.setContentLength((int) Files.size(filePath));
        
        // Stream the file content
        try (InputStream in = Files.newInputStream(filePath);
             OutputStream out = response.getOutputStream()) {
            
            byte[] buffer = new byte[4096];
            int bytesRead;
            while ((bytesRead = in.read(buffer)) != -1) {
                out.write(buffer, 0, bytesRead);
            }
        }
    }
}